/**
 * MedX fileupload forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * COA and compliance document uploads.
 */
const FILEUPLOAD_TOKENS = Object.freeze({
  primary: { value: "forms-fileupload-primary", scope: "forms" },
  secondary: { value: "forms-fileupload-secondary", scope: "forms" },
  muted: { value: "forms-fileupload-muted", scope: "forms" },
  accent: { value: "forms-fileupload-accent", scope: "forms" },
  surface: { value: "forms-fileupload-surface", scope: "forms" },
});

const FILEUPLOAD_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FILEUPLOAD_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const fileuploadRegistry = new Map();
const FILEUPLOAD_listeners = new Set();
let FILEUPLOAD_seq = 0;

function createFileuploadId(prefix = "medx-forms-fileupload") {
  FILEUPLOAD_seq += 1;
  return `${prefix}-${FILEUPLOAD_seq}`;
}

function registerFileupload(config = {}) {
  const entryId = config.id ?? createFileuploadId();
  const preset = FILEUPLOAD_PRESETS[config.preset ?? "default"] ?? FILEUPLOAD_PRESETS.default;
  const token = FILEUPLOAD_TOKENS[config.token ?? preset.token] ?? FILEUPLOAD_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FILEUPLOAD_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  fileuploadRegistry.set(entryId, entry);
  notifyFileuploadListeners("register", entry);
  return entry;
}

function updateFileupload(id, patch = {}) {
  const entry = fileuploadRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFileuploadListeners("update", entry);
  return entry;
}

function resolveFileupload(id) {
  const entry = fileuploadRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFileuploadEntries(filter = {}) {
  let items = Array.from(fileuploadRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFileuploadEvent(listener) {
  FILEUPLOAD_listeners.add(listener);
  return () => FILEUPLOAD_listeners.delete(listener);
}

function notifyFileuploadListeners(type, entry) {
  for (const listener of FILEUPLOAD_listeners) {
    try {
      listener({ type, entry, registrySize: fileuploadRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:fileupload] listener error", err.message);
    }
  }
}

function getFileuploadMetrics() {
  const items = listFileuploadEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FILEUPLOAD_TOKENS).length,
    presets: Object.keys(FILEUPLOAD_PRESETS).length,
  };
}

async function runMedxFileupload() {
  console.log("[medx:ui:forms:fileupload] runtime initialized");
  console.log(`[medx:ui:forms:fileupload] tokens=${Object.keys(FILEUPLOAD_TOKENS).length} presets=${Object.keys(FILEUPLOAD_PRESETS).length}`);

  const events = [];
  onFileuploadEvent((e) => events.push(e.type));

  const domains = Object.keys(FILEUPLOAD_SUPPLY_CHAIN);
  const presets = Object.keys(FILEUPLOAD_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerFileupload({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/fileupload" },
    });
  }

  const first = listFileuploadEntries()[0];
  if (first) updateFileupload(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFileuploadMetrics();
  const resolved = first ? resolveFileupload(first.id) : null;

  console.log(`[medx:ui:forms:fileupload] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:fileupload] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:fileupload] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:fileupload] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:fileupload] bootstrap complete");
}

module.exports = runMedxFileupload;
